function calculate({ currentAssessedValue, currentTaxRate, currentExemptionAmount, proposedTaxRate, proposedExemptionAmount, proposedWealthTaxThreshold, proposedWealthTaxRate, reassessmentPercentageChange }) {
    // Ensure all inputs are treated as numbers, with defaults for optional fields
    currentAssessedValue = parseFloat(currentAssessedValue) || 0;
    currentTaxRate = parseFloat(currentTaxRate) || 0; // Stored as percentage, e.g., 1.25 for 1.25%
    currentExemptionAmount = parseFloat(currentExemptionAmount) || 0;
    proposedTaxRate = parseFloat(proposedTaxRate) || 0;
    proposedExemptionAmount = parseFloat(proposedExemptionAmount) || 0;
    proposedWealthTaxThreshold = parseFloat(proposedWealthTaxThreshold) || 0;
    proposedWealthTaxRate = parseFloat(proposedWealthTaxRate) || 0;
    reassessmentPercentageChange = parseFloat(reassessmentPercentageChange) || 0;

    // Convert rates from percentage to decimal for calculations
    const currentTaxRateDecimal = currentTaxRate / 100;
    const proposedTaxRateDecimal = proposedTaxRate / 100;
    const proposedWealthTaxRateDecimal = proposedWealthTaxRate / 100;

    // 1. Calculate Current Annual Property Tax
    // Taxable value cannot be negative due to exemptions
    const taxableValueCurrent = Math.max(0, currentAssessedValue - currentExemptionAmount);
    const currentAnnualPropertyTax = taxableValueCurrent * currentTaxRateDecimal;

    // 2. Calculate New Estimated Assessed Value
    // Handle potential negative reassessment percentage
    const newAssessedValue = currentAssessedValue * (1 + reassessmentPercentageChange / 100);

    // 3. Calculate Proposed Annual Property Tax (Traditional component, excluding wealth tax)
    // Taxable value cannot be negative due to exemptions
    const taxableValueProposed = Math.max(0, newAssessedValue - proposedExemptionAmount);
    const proposedAnnualPropertyTax = taxableValueProposed * proposedTaxRateDecimal;

    // 4. Calculate Estimated Annual Wealth Tax Liability (property-based)
    let estimatedWealthTaxLiability = 0;
    // Only apply wealth tax if a rate is specified
    if (proposedWealthTaxRateDecimal > 0) {
        if (proposedWealthTaxThreshold <= 0) {
            // If threshold is 0 or negative, wealth tax applies to the entire newAssessedValue
            estimatedWealthTaxLiability = newAssessedValue * proposedWealthTaxRateDecimal;
        } else if (newAssessedValue > proposedWealthTaxThreshold) {
            // If value exceeds a positive threshold, tax applies to the amount above the threshold
            estimatedWealthTaxLiability = (newAssessedValue - proposedWealthTaxThreshold) * proposedWealthTaxRateDecimal;
        }
        // Ensure wealth tax is not negative
        estimatedWealthTaxLiability = Math.max(0, estimatedWealthTaxLiability);
    }

    // 5. Calculate Total Proposed Annual Tax Bill
    const totalProposedAnnualTaxBill = proposedAnnualPropertyTax + estimatedWealthTaxLiability;

    // 6. Calculate Net Annual Tax Change
    const netAnnualTaxChange = totalProposedAnnualTaxBill - currentAnnualPropertyTax;

    // 7. Calculate Percentage Tax Change
    let percentageTaxChange = 0;
    if (currentAnnualPropertyTax > 0) {
        percentageTaxChange = (netAnnualTaxChange / currentAnnualPropertyTax) * 100;
    } else if (totalProposedAnnualTaxBill > 0) {
        // Special case: current tax was 0, but proposed tax is now > 0. Represent as a significant increase.
        // For display purposes, an infinite percentage increase is not helpful. We'll show the absolute change.
        // If we must show a percentage, consider a very high arbitrary number or a flag.
        // For now, if current tax is 0 and proposed is > 0, percentage change remains 0 as absolute change is more informative.
        // If both are 0, percentage change is 0.
    }

    return {
        currentAnnualPropertyTax: Math.max(0, currentAnnualPropertyTax), // Ensure non-negative output
        newAssessedValue: Math.max(0, newAssessedValue), // Ensure non-negative output
        proposedAnnualPropertyTax: Math.max(0, proposedAnnualPropertyTax), // Ensure non-negative output
        estimatedWealthTaxLiability: Math.max(0, estimatedWealthTaxLiability), // Ensure non-negative output
        totalProposedAnnualTaxBill: Math.max(0, totalProposedAnnualTaxBill), // Ensure non-negative output
        netAnnualTaxChange,
        percentageTaxChange
    };
}
